// This is a simple interface which specifies echo.Route addition functions which
// are present on both echo.Echo and echo.Group, since we want to allow using
// either of them for path registration
type EchoRouter interface {
	CONNECT(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	DELETE(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	GET(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	HEAD(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	OPTIONS(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	PATCH(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	POST(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	PUT(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	TRACE(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
}

// RegisterHandlers adds each server route to the EchoRouter.
func RegisterHandlers(router EchoRouter, si ServerInterface) {
	RegisterHandlersWithBaseURL(router, si, "")
}

// Registers handlers, and prepends BaseURL to the paths, so that the paths
// can be served under a prefix.
func RegisterHandlersWithBaseURL(router EchoRouter, si ServerInterface, baseURL string) {

	wrapper := ServerInterfaceWrapper{
		Handler: si,
	}

	router.GET(baseURL+"/", wrapper.Root)
	router.GET(baseURL+"/announcements", wrapper.GetAnnouncements)
	router.POST(baseURL+"/announcements", wrapper.CreateAnnouncement)
	router.DELETE(baseURL+"/announcements/:announcementId", wrapper.DeleteAnnouncement)
	router.GET(baseURL+"/announcements/:announcementId", wrapper.GetAnnouncement)
	router.PUT(baseURL+"/announcements/:announcementId", wrapper.UpdateAnnouncement)
	router.GET(baseURL+"/app-status", wrapper.GetAppStatus)
	router.PUT(baseURL+"/app-status", wrapper.UpdateAppStatus)
	router.GET(baseURL+"/apps", wrapper.GetApps)
	router.POST(baseURL+"/apps", wrapper.CreateApp)
	router.DELETE(baseURL+"/apps/:appId", wrapper.DeleteApp)
	router.GET(baseURL+"/apps/:appId", wrapper.GetApp)
	router.PUT(baseURL+"/apps/:appId", wrapper.UpdateApp)
	router.GET(baseURL+"/categories", wrapper.GetCategories)
	router.POST(baseURL+"/categories", wrapper.CreateCategory)
	router.DELETE(baseURL+"/categories/:categoryId", wrapper.DeleteCategory)
	router.GET(baseURL+"/categories/:categoryId", wrapper.GetCategory)
	router.PUT(baseURL+"/categories/:categoryId", wrapper.UpdateCategory)
	router.GET(baseURL+"/health", wrapper.HealthCheck)
	router.POST(baseURL+"/images/presigned-url", wrapper.CreatePresignedUrl)
	router.POST(baseURL+"/publish", wrapper.PostPublish)
	router.GET(baseURL+"/questions", wrapper.GetQuestions)
	router.POST(baseURL+"/questions", wrapper.CreateQuestion)
	router.DELETE(baseURL+"/questions/:questionId", wrapper.DeleteQuestion)
	router.GET(baseURL+"/questions/:questionId", wrapper.GetQuestion)
	router.PUT(baseURL+"/questions/:questionId", wrapper.UpdateQuestion)
	router.GET(baseURL+"/users", wrapper.GetUsers)
	router.GET(baseURL+"/users/:userId", wrapper.GetUser)
	router.GET(baseURL+"/users/:userId/answers", wrapper.GetUserAnswers)
	router.GET(baseURL+"/workbooks", wrapper.GetWorkbooks)
	router.POST(baseURL+"/workbooks", wrapper.CreateWorkbook)
	router.DELETE(baseURL+"/workbooks/:workbookId", wrapper.DeleteWorkbook)
	router.GET(baseURL+"/workbooks/:workbookId", wrapper.GetWorkbook)
	router.PUT(baseURL+"/workbooks/:workbookId", wrapper.UpdateWorkbook)

}

